import { type ReactNode } from 'react';
import type { WithId } from '../../../types/with-id.js';
/**
 * The annotations marker slot props
 * @public
 */
export interface BaseMarkerProps {
    /**
     * Arbitrary metadata attached to the marker, forwarded into AnnotationsActionsPayload
     */
    [key: string]: unknown;
    /**
     * The marker title
     */
    title?: string;
    /**
     * The marker symbol, which can be a letter, an emoji, an icon or a Unicode character
     */
    symbol?: ReactNode;
    /**
     * The marker description
     */
    description?: string;
    /**
     * The marker background, supporting any valid CSS color
     * @defaultValue Colors.Charts.Categorical.Color01.Default
     */
    color?: string;
    /**
     * The priority of the marker, which can be used to specify which marker will be rendered on top of the other, in case of overlapping,
     * and also will specify the order of the tooltip items in case of having the same range/value.
     * @defaultValue 0
     */
    priority?: number;
    /**
     * Specify whether a particular marker should hide.
     * @defaultValue false
     */
    hidden?: boolean;
}
/**
 * Numerical marker props
 * @public
 */
export interface NumericalMarkerProps {
    /**
     * Starting point of the marker
     */
    start: number;
    /**
     * Ending point of the marker. If not set, the marker will represent a value instead of a range
     */
    end?: number;
}
/**
 * Time based marker props
 * @public
 */
export interface TimeMarkerProps {
    /**
     * Starting point of the marker
     */
    start: Date;
    /**
     * Ending point of the marker. If not set, the marker will be a timestamp instead of a timeframe
     */
    end?: Date;
}
/**
 * The annotations marker props. Supporting numerical and time based data
 * @public
 */
export type AnnotationsMarkerProps = BaseMarkerProps & (TimeMarkerProps | NumericalMarkerProps);
/** @internal */
export type AnnotationsMarkerConfig = WithId<AnnotationsMarkerProps> & {
    color: string;
    priority: number;
    hidden: boolean;
};
